dslRule:
/*!id: deprecated-for-removal-since
<!description: Mark @Deprecated methods with forRemoval = true and a specific since version for planned removal. The 'since' attribute value is specific to this context and reduces general reusability.
<!severity: INFO>
<!minJavaVersion: 9>
<!tags: modernization, java9, deprecation>

@java.lang.Deprecated :: sourceVersionGE(9)
=> @java.lang.Deprecated(forRemoval = true, since = "2025-03")
;;

/*!id: deprecated-for-removal-flag
<!description: Mark bare @Deprecated annotations with 'forRemoval = true' and 'since="2025-03"'.
This applies to annotations without explicit 'forRemoval' or 'since' attributes, ensuring they are properly flagged for future removal.
<!severity: info>
<!minJavaVersion: 9>
<!tags: modernization, java9, annotations, deprecated-api>
@java.lang.Deprecated :: sourceVersionGE(9)
=> @java.lang.Deprecated(forRemoval = true, since = "2025-03")
;;

dslRuleAfterChange:
@java.lang.Deprecated
=> DELETE
;;

// A more specific rule with context might be:
@java.lang.Deprecated
  :: parentMatches("new org.eclipse.ui.dialogs.ListSelectionDialog($parentShell, $input, $contentProvider, $labelProvider, $message)")
=> DELETE
;;
